from collections import deque

def longest_path_dag(n, adj):
    """
    n   : number of vertices (0..n-1)
    adj : adjacency list dict {u: [(v, weight), ...]}
    Returns length of the longest path starting from any vertex.
    """
    indegree = [0] * n
    for u in adj:
        for v, _ in adj[u]:
            indegree[v] += 1

    queue = deque(u for u in range(n) if indegree[u] == 0)
    dp    = [0] * n   # longest path ending at each node

    while queue:
        u = queue.popleft()
        for v, w in adj.get(u, []):
            dp[v] = max(dp[v], ___________)
            indegree[v] -= 1
            if indegree[v] == 0:
                queue.append(v)
    return max(dp)
